// 1. Fetch all records coming from the Airtable node securely using modern syntax
const items = $input.all();

let tableRows = '';
// Initialize counters for the days of the week
const daysCount = { 'Lunedì': 0, 'Martedì': 0, 'Mercoledì': 0, 'Giovedì': 0, 'Venerdì': 0, 'Sabato': 0, 'Domenica': 0 };
const daysMapping = ['Domenica', 'Lunedì', 'Martedì', 'Mercoledì', 'Giovedì', 'Venerdì', 'Sabato'];

// Most requested topics counters
let rulesCount = 0;
let variantsCount = 0;
let generalCount = 0;

// Loop through each item from Airtable
for (const item of items) {
    const fields = item.json.fields;
    if (!fields) continue;

    const question = fields.Question || 'Senza domanda';
    const answer = fields.Answer || 'Nessuna risposta fornita';
    const dateStr = fields.Date;

    // A. Build HTML table rows dynamically
    tableRows += `<tr><td>${question}</td><td>${answer}</td></tr>`;

    // B. Process the day of the week for the chart
    if (dateStr) {
        const dateObj = new Date(dateStr);
        const dayName = daysMapping[dateObj.getDay()];
        if (daysCount[dayName] !== undefined) {
            daysCount[dayName]++;
        }
    }

    // C. Classify topics based on keywords
    const lowerQ = question.toLowerCase();
    if (lowerQ.includes('vince') || lowerQ.includes('regole') || lowerQ.includes('gioca')) {
        rulesCount++;
    } else if (lowerQ.includes('varianti') || lowerQ.includes('tipi')) {
        variantsCount++;
    } else {
        generalCount++;
    }
}

// 2. Generate the final HTML template injecting the processed metrics
const htmlContent = `
<!DOCTYPE html>
<html lang="it">
<head>
    <meta charset="UTF-8">
    <title>Dashboard Analitica - Hopscotch</title>
    <script src="https://cdn.jsdelivr.net/npm/chart.js"></script>
    <style>
        body { font-family: 'Segoe UI', Arial, sans-serif; margin: 40px; background-color: #f8fafc; color: #334155; }
        .container { max-width: 1000px; margin: auto; background: white; padding: 30px; border-radius: 12px; box-shadow: 0 4px 6px rgba(0,0,0,0.05); }
        h1 { color: #1e3a8a; border-bottom: 3px solid #3b82f6; padding-bottom: 10px; margin-top: 0; }
        h2 { color: #1e40af; margin-top: 30px; }
        .grid { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; margin-top: 20px; }
        .card { background: #f1f5f9; padding: 15px; border-radius: 8px; }
        table { width: 100%; border-collapse: collapse; margin-top: 15px; background: white; }
        th, td { padding: 12px; text-align: left; border-bottom: 1px solid #e2e8f0; font-size: 14px; }
        th { background: #3b82f6; color: white; }
        .chart-container { max-width: 450px; margin: auto; }
        ul { padding-left: 20px; }
        li { margin-bottom: 8px; }
    </style>
</head>
<body>
    <div class="container">
        <h1>🎮 Dashboard RAG Agent - Hopscotch</h1>

        <div class="grid">
            <div class="card">
                <h2>📊 Temi più richiesti</h2>
                <ul>
                    <li><strong>Regole e Come Vince:</strong> ${rulesCount} richieste</li>
                    <li><strong>Varianti del Gioco:</strong> ${variantsCount} richieste</li>
                    <li><strong>Generale / Altro:</strong> ${generalCount} richieste</li>
                </ul>
            </div>
            <div class="card">
                <h2>📈 Risposte per Giorno della Settimana</h2>
                <div class="chart-container">
                    <canvas id="weeklyChartCanvas"></canvas>
                </div>
            </div>
        </div>

        <h2>📜 Registro delle Risposte Raccolte</h2>
        <table>
            <thead>
                <tr>
                    <th>Domanda Utente</th>
                    <th>Risposta Fornita</th>
                </tr>
            </thead>
            <tbody>
                ${tableRows}
            </tbody>
        </table>
    </div>

    <script>
        const ctx = document.getElementById('weeklyChartCanvas').getContext('2d');
        new Chart(ctx, {
            type: 'bar',
            data: {
                labels: ['Lunedì', 'Martedì', 'Mercoledì', 'Giovedì', 'Venerdì', 'Sabato', 'Domenica'],
                datasets: [{
                    label: 'Numero di Interazioni',
                    data: [${daysCount['Lunedì']}, ${daysCount['Martedì']}, ${daysCount['Mercoledì']}, ${daysCount['Giovedì']}, ${daysCount['Venerdì']}, ${daysCount['Sabato']}, ${daysCount['Domenica']}],
                    backgroundColor: '#3b82f6',
                    borderRadius: 5
                }]
            },
            options: {
                responsive: true,
                scales: { y: { beginAtZero: true, ticks: { stepSize: 1 } } }
            }
        });
    </script>
</body>
</html>
`;

// Return the structured JSON to the Respond to Webhook node
return [{
    json: {
        html: htmlContent
    }
}];
